from django.core.cache import cache
import hashlib

def get_cached(key):
    return cache.get(key)

def set_cached(key, value, timeout=3600):
    cache.set(key, value, timeout)

def cache_payment_data(order_id, user_id, data):
    """Cache payment-related data for faster processing."""
    cache_key = f'payment:{order_id}:{user_id}'
    cache.set(cache_key, data, timeout=300)  # 5 minutes
    return cache_key

def get_payment_cache(order_id, user_id):
    """Retrieve cached payment data."""
    cache_key = f'payment:{order_id}:{user_id}'
    return cache.get(cache_key)
